{
  "formal_minutes": {
    "confirmed_decisions": [
      {
        "decision": "공개 릴리스 목표는 스모크 테스트가 통과하면 금요일 15:00 KST로 둔다.",
        "condition": "스모크 테스트 통과"
      },
      {
        "decision": "packageName mismatch가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트를 검토한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 바꾸자는 제안",
        "resolution": "거절",
        "rationale": "먼저 패키지 설정을 확인해야 하며, 계약이 잘못된 경우에만 스크립트를 검토하기로 함"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 공개 릴리스는 내부 스트레치 목표로만 유지한다."
      }
    ],
    "non_decisions": [
      {
        "topic": "README install steps는 목요일까지 가능하면 검토하자는 의견이 있었지만, 소유자는 지정되지 않았다."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로는 릴리스를 지연시킬 수 있다."
      },
      {
        "risk": "README install steps가 오래되면 릴리스 노트가 사용자를 오도할 수 있다."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한은 누구에게 있는가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 포함할지 여부는 어떻게 할 것인가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "예정",
      "source_certainty": "명시됨"
    },
    {
      "owner": "Doyun",
      "task": "failure triage note를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "예정",
      "source_certainty": "명시됨"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과가 올라오면 생성된 tarball 경로를 확인한다.",
      "due": null,
      "status": "대기",
      "source_certainty": "명시됨"
    },
    {
      "owner": null,
      "task": "README install steps를 목요일까지 가능하면 검토한다.",
      "due": "목요일(가능하면)",
      "status": "미지정",
      "source_certainty": "부분 명시"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 스모크 테스트 재실행 결과를 먼저 확인한다.",
      "그 다음 Hara의 tarball 경로 확인 결과를 검증한다.",
      "README install steps의 실제 상태와 리뷰 담당자 유무를 재확인한다.",
      "최종 릴리스 승인 권한과 수요일 스트레치 목표의 릴리스 노트 포함 여부는 아직 미확정으로 둔다."
    ],
    "do_not_invent": [
      "고객명이나 외부 파트너명을 채우지 않는다.",
      "예산, 보안 사고, 프로덕션 장애, 법무 승인 요구를 추가하지 않는다.",
      "Hara의 정확한 마감 시각을 만들지 않는다.",
      "README 리뷰의 소유자나 hard deadline을 만들어내지 않는다."
    ]
  },
  "non_invention_rules": [
    "명시된 사실만 사용하고 고객, 외부 파트너, 예산, 보안, 장애, 법무 항목은 추가하지 않는다.",
    "원문에 나온 상대 시점은 그대로 보존하고 새로운 절대 날짜는 계산하지 않는다.",
    "수요일은 내부 스트레치 목표이며 최종 공개 릴리스 결정으로 바꾸지 않는다.",
    "README 리뷰 담당자와 Hara의 정확한 마감 시각은 추정하지 않는다."
  ]
}
